from flask import current_app

invoices_blueprint = Blueprint('invoices', __name__)

@invoices_blueprint.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Assuming invoices are stored in a directory with the same name as the invoice ID
    user_id = current_app.config['AUTHENTICATED_USER_ID']  # Get the authenticated user's ID from the auth middleware
    invoice_dir = f'/path/to/invoices/{user_id}/{invoice_id}'
    
    if not os.path.exists(invoice_dir):
        return 'Invoice not found', 404
    
    # Assuming the PDF file is named after the invoice ID and has a .pdf extension
    pdf_filename = f'{invoice_id}.pdf'
    pdf_path = os.path.join(invoice_dir, pdf_filename)
    
    if not os.path.exists(pdf_path):
        return 'PDF file not found', 404
    
    # Check if the user has permission to download this invoice (e.g., based on their role or permissions)
    if not current_app.config['USER_HAS_PERMISSION'](user_id, invoice_id):
        return 'Permission denied', 403
    
    return send_file(pdf_path, as_attachment=True, attachment_filename=pdf_filename)